<template>
  <v-row class="align-center">
    <v-col cols="8" md="3" class="d-flex align-center">
      <span class="text-body-1">{{ label }}</span>
    </v-col>
    <v-col cols="4" md="1" class="d-flex justify-center align-center pa-0">
      <div class="text-h5 mr-5">
        {{ modelValue || '-' }}
        <span class="text-body-1">/ {{ length }}</span>
      </div>
    </v-col>
    <v-col cols="12" md="8" class="d-flex align-middle pa-2">
      <v-rating
        :model-value="modelValue"
        :item-labels="itemLabels"
        :length="length"
        size="x-large"
        density="compact"
        :active-color="negative ? 'blue' : 'orange-accent-4'" 
        color="grey"
        @update:model-value="emit('update:modelValue', $event)"
      ></v-rating>
    </v-col>
  </v-row>
</template>

<script setup>
import { ref, defineProps, defineEmits } from 'vue'

const props = defineProps({
  label: {
    type: String,
    required: true
  },
  modelValue: {
    type: Number,
    default: 0
  },
  itemLabels: {
    type: Array,
    default: () => ['', '', '', '', '']
  },
  negative: {
    type: Boolean,
    default: false
  },
})

const length = ref(props.itemLabels.length)

const emit = defineEmits(['update:modelValue'])
</script>

<style>
.v-rating__item .v-btn {
  width: 3.2em;
}
</style>